mapper.insert:
        INSERT INTO MOVIES
		 (MOVIE_ID
		, POSTER_URL
		, TITLE
		, MOVIE_RATING
		, OPEN_DATE
		, OPEN_COUNTRY
		, RUNNING_TIME
		, INTRODUCE
		, SYNOPSIS
		, ORIGNAL_TITLE
		, LANGUAGE
		, BUDGET
		, PROFIT) VALUES
		 ('MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIES_PK.NEXTVAL, 6, '0')
		, #{posterUrl}
		, #{title}
		, #{movieRating}
		, TO_DATE(#{openDate}, 'YYYY-MM-DD hh:mi:ss')
		, #{openCountry}
		, #{runningTime}
		, #{introduce}
		, #{synopsis}
		, #{orignalTitle}
		, #{language}
		, #{budget}
		, #{profit})
